/**
 * This is the quantitative modular reasoning test
 * 
 * The quantitative modular reasoning evaluation category tests whether quantitative models 
 * generated by LLMS include key modular processes and mechanisms necessary for a particular system.
 * Building on the quantitative causal reasoning evaluation, this evaluation evaluates the modular
 * capabilities of LLMs, including the ability to create modules with key causal relationships
 * and to create valid cross-module relationships.
 * 
 * The evaluation works similarly to the quantitative causal reasoning evaluation. However, a list of
 * expected modules in the generated model is passed as an additional expectation. The generated model
 * must exactly match the list of expected modules for the test to pass. Additionally, variables that
 * are expected to be a cross-level ghost of another can be specified, and any model that contains
 * direct flow relationships between two components in different modules (without ghosting) is declared invalid.
 * 
 * @module categories/quantitativeModularReasoning
 */

import utils from '../../utilities/utils.js';

// Note: pluralize import removed as it's not used in this evaluation

/** generic prompt used for all tests */
const prompt = 
`
Please give me a quantitative model that captures the key causal processes described in the background information.
Make sure to create a model with exactly the specified modules; do not add any additional modules beyond what is specified.
`;
/** generic problem statement used for all tests */
const problemStatement = "I'm trying to understand the key causal mechanisms that drive this system's behavior over time.";

/**
 * Generates a test case with expert knowledge and expected causal processes
 * @param {string} name Test name
 * @param {string} timeUnit Time units for the model (e.g., "month", "year")
 * @param {string} backgroundKnowledge Expert description of the system
 * @param {Array} expectedProcesses List of key processes that should be present
 * @param {Array} expectedModules List of key modules that should match the model exactly
 * @returns {Object} Test case with prompt, parameters, and expectations
 */

const generateTest = function(name, timeUnit, backgroundKnowledge, expectedProcesses, expectedModules) {
    return {
        name: name,
        prompt: prompt,
        additionalParameters: {
            problemStatement: problemStatement,
            backgroundKnowledge: 
            `Please rely on the following expert knowledge as much as possible when creating your model.\n\n${backgroundKnowledge}`,
            supportsArrays: true,
            supportsModules: true,
        },
        expectations: {
            timeUnit: timeUnit,
            expectedProcesses: expectedProcesses,
            expectedModules: expectedModules
        }
    };
};

/**
 * Checks if a process is represented in the generated model
 * @param {Object} process Expected process definition
 * @param {Object} generatedModel The model generated by the LLM
 * @returns {boolean} True if the process is adequately represented
 */
const processIsPresent = function(process, generatedModel) {
    const variables = generatedModel.variables || [];
    const relationships = generatedModel.relationships || [];
    
    // Check if required stocks are present (require 100% match)
    if (process.requiredStocks) {
        for (const stockName of process.requiredStocks) {
            const stock = variables.find(v => 
                v.type === 'stock' && 
                utils.evalsVariableNameMatches(v.name, stockName)
            );
            if (!stock) {
                return false;
            }
        }
    }
    
    // Check if required flows are present (require 100% match)
    if (process.requiredFlows) {
        for (const flowName of process.requiredFlows) {
            const flow = variables.find(v => 
                v.type === 'flow' && 
                utils.evalsVariableNameMatches(v.name, flowName)
            );
            if (!flow) {
                return false;
            }
        }
    }
    
    // Check if required relationships are present (focus on key causal patterns with flexible variable matching)
    if (process.requiredRelationships) {
        for (const reqRel of process.requiredRelationships) {
            const relationshipExists = relationships.some(rel => {
                const fromMatches = variables.some(v => utils.evalsVariableNameMatches(v.name, reqRel.from) && utils.evalsVariableNameMatches(rel.from, v.name));
                const toMatches = variables.some(v => utils.evalsVariableNameMatches(v.name, reqRel.to) && utils.evalsVariableNameMatches(rel.to, v.name));
                const polarityMatches = !reqRel.polarity || rel.polarity === reqRel.polarity;
                return fromMatches && toMatches && polarityMatches;
            });
            if (!relationshipExists) {
                return false;
            }
        }
    }
    
    // Check if required variables with specific types are present (require 100% match)
    if (process.requiredVariables) {
        for (const keyVar of process.requiredVariables) {
            const variable = variables.find(v => {
                const nameMatches = utils.evalsVariableNameMatches(v.name, keyVar.name);
                const ghostMatches = utils.evalsVariableNameMatchesStrict(v.crossLevelGhostOf || "", keyVar.crossLevelGhostOf || "");
                const typeMatches = !keyVar.type || v.type === keyVar.type;
                return nameMatches && typeMatches && ghostMatches;
            });
            if (!variable) {
                return false;
            }
        }
    }
    
    return true;
};

/**
 * This method compares the generated response to the ground truth and returns a list of failure objects
 * @param {Object} generatedResponse The response from the engine
 * @param {Object} expectations The expected processes and time unit information
 * @returns {Array<Object>} A list of failures with type and details.
 */
export const evaluate = function(generatedResponse, expectations) {
    const generatedModel = generatedResponse?.model || {};
    const expectedProcesses = expectations.expectedProcesses || [];
    const expectedModules = expectations.expectedModules || [];
    const failures = [];

    // Basic Quantitative Structure Check
    const variables = generatedModel.variables || [];
    const stocks = variables.filter(v => v.type === 'stock');
    const flows = variables.filter(v => v.type === 'flow');
    
    if (stocks.length === 0) {
        failures.push({
            type: "No stocks found",
            details: "A quantitative model should contain at least one stock variable"
        });
    }
    
    if (flows.length === 0) {
        failures.push({
            type: "No flows found", 
            details: "A quantitative model should contain at least one flow variable"
        });
    }

    // Get Modules
    const modules = [];
    for (const v of variables) {
        const vmodule = utils.evalsGetModuleName(v.name);
        if (vmodule !== "" && !modules.includes(vmodule)) modules.push(vmodule);
    }

    // Module List must match exactly
    for (const m of modules) {
        if (!expectedModules.includes(m)) {
            failures.push({
                type: "Unexpected module",
                details: `Module "${m}" was unexpectedly created.`
            });
        }
    }

    for (const m of expectedModules) {
        if (!modules.includes(m)) {
            failures.push({
                type: "Missing module",
                details: `Module "${m}" is not adequately represented.`
            });
        }
    }
    
    // Fail if two components from different modules are directly linked (without ghosting)
    for (const f of generatedModel.relationships || []) {
        const fromModule = utils.evalsGetModuleName(f.from || "");
        const toModule = utils.evalsGetModuleName(f.to || "")
        if (!utils.evalsVariableNameMatches(fromModule, toModule)) {
            failures.push({
                type: "Invalid relationship",
                details: `Relationship between "${f.from}" and "${f.to}" is invalid (different modules without ghosting)`
            });
        }
    }

    // Check each expected process
    for (const process of expectedProcesses) {
        if (!processIsPresent(process, generatedModel)) {
            const missingElements = [];
            const relationships = generatedModel.relationships || [];
            
            // Identify what's missing
            if (process.requiredStocks) {
                const missingStocks = process.requiredStocks.filter(stockName => 
                    !variables.some(v => v.type === 'stock' && utils.evalsVariableNameMatches(v.name, stockName))
                );
                if (missingStocks.length > 0) {
                    missingElements.push(`stocks: ${missingStocks.join(', ')}`);
                }
            }
            
            if (process.requiredFlows) {
                const missingFlows = process.requiredFlows.filter(flowName =>
                    !variables.some(v => v.type === 'flow' && utils.evalsVariableNameMatches(v.name, flowName))
                );
                if (missingFlows.length > 0) {
                    missingElements.push(`flows: ${missingFlows.join(', ')}`);
                }
            }
            
            if (process.requiredRelationships) {
                const missingRelationships = process.requiredRelationships.filter(reqRel => {
                    return !relationships.some(rel => {
                        const fromMatches = variables.some(v => utils.evalsVariableNameMatches(v.name, reqRel.from) && utils.evalsVariableNameMatches(rel.from, v.name));
                        const toMatches = variables.some(v => utils.evalsVariableNameMatches(v.name, reqRel.to) && utils.evalsVariableNameMatches(rel.to, v.name));
                        const polarityMatches = !reqRel.polarity || rel.polarity === reqRel.polarity;
                        return fromMatches && toMatches && polarityMatches;
                    });
                });
                if (missingRelationships.length > 0) {
                    const relStrings = missingRelationships.map(rel => 
                        `${rel.from} → ${rel.to}${rel.polarity ? ` (${rel.polarity})` : ''}`
                    );
                    missingElements.push(`relationships: ${relStrings.join(', ')}`);
                }
            }
            
            if (process.requiredVariables) {
                const missingVars = process.requiredVariables.filter(keyVar =>
                    !variables.some(v => {
                        const nameMatches = utils.evalsVariableNameMatches(v.name, keyVar.name);
                        const ghostMatches = utils.evalsVariableNameMatchesStrict(v.crossLevelGhostOf || "", keyVar.crossLevelGhostOf || "");
                        const typeMatches = !keyVar.type || v.type === keyVar.type;
                        return nameMatches && ghostMatches && typeMatches;
                    })
                );
                if (missingVars.length > 0) {
                    missingElements.push(`variables: ${missingVars.map(v => 
                        `${v.name}${v.crossLevelGhostOf ? ' which ghosts ' : ''}${v.crossLevelGhostOf || ''}`
                    ).join(', ')}`);
                }
            }

            // If no specific missing elements identified, report that process requirements are not satisfied
            // This should theoretically never happen if processIsPresent logic matches error detection logic
            if (missingElements.length === 0) {
                missingElements.push(`process requirements not satisfied (unable to identify specific missing elements)`);
            }

            failures.push({
                type: "Missing key process",
                details: `Process "${process.name}" is not adequately represented. Missing: ${missingElements.join('; ')}`
            });
        }
    }

    return failures;
};

/**
 * Returns the description for this category
 * @returns {string} The description describing this category
 */
export const description = () => {
    return `The quantitative modular reasoning test evaluates whether quantitative models generated by LLMs
    can properly organize key process and causal mechanisms into modular layers, and correctly create
    cross-module processes and relationships. These evaluations assess the substantive quality of modular reasoning
    in stock-and-folow models by comparing generated models against expert-identified stocks, flows, variables, and
    relationships across domains like predator-prey ecosystems and urban development.`
};

/**
 * The groups of tests to be evaluated as a part of this category
 */
export const groups = {
    "noModules": [
        generateTest(
            "Consulting Business Model",
            "year",
            `
            At a certain business, employees are sorted in a three-role hierarchy.
            New hirees start with the "rookie" status.
            Rookies that perform well are promoted to associates.
            Associates that perform well are promoted to partners.
            To keep the hierarchy stable, the business promotes a strict percentage of each role every year.
            Some employees may also leave the company, whether due to personal reasons or exceptionally poor performance.
            A stable percentage of employees at each level of the company leave the company each year.
            The business also onboards a constant number of new hirees every year.

            Use these variable names:
            rookies, associates, partners, promotion_rate, departure_rate, hire_rate,
            rookie_promotions, associate_promotions, rookie_hires,
            rookie_departures, associate_departures, partner_departures

            Do not create any modules in this model.
            `,
            [
                {
                    name: "Business Hierarchy",
                    requiredStocks: ["rookies", "associates", "partners"]
                },
                {
                    name: "Promotion Dynamics",
                    requiredVariables: [
                        { name: "promotion_rate" },
                        { name: "hire_rate" }
                    ],
                    requiredFlows: ["rookie_promotions", "associate_promotions", "rookie_hires"],
                    requiredRelationships: [
                        { from: "promotion_rate", to: "rookie_promotions", polarity: "+" },
                        { from: "promotion_rate", to: "associate_promotions", polarity: "+" },
                        { from: "hire_rate", to: "rookie_hires", polarity: "+" },

                        { from: "rookies", to: "rookie_promotions", polarity: "+" },
                        { from: "rookie_promotions", to: "associates", polarity: "+" },
                        { from: "associates", to: "associate_promotions", polarity: "+" },
                        { from: "associate_promotions", to: "partners", polarity: "+" },
                    ]
                },
                {
                    name: "Departure Dynamics",
                    requiredVariables: [
                        { name: "departure_rate" },
                    ],
                    requiredFlows: ["rookie_departures", "associate_departures", "partner_departures"],
                    requiredRelationships: [
                        { from: "departure_rate", to: "rookie_departures", polarity: "+" },
                        { from: "departure_rate", to: "associate_departures", polarity: "+" },
                        { from: "departure_rate", to: "partner_departures", polarity: "+" },

                        { from: "rookie_departures", to: "rookies", polarity: "-" },
                        { from: "associate_departures", to: "associates", polarity: "-" },
                        { from: "partner_departures", to: "partners", polarity: "-" },
                    ]
                }
            ],
            []
        )
    ],
    "twoModules": [
        generateTest(
            "Predator-Prey System with Two Modules",
            "day",
            `
            In a certain ecosystem, there are two animal populations: foxes and chickens.
            Initially, chickens significantly outnumber foxes.
            The chickens reproduce at a steady percentage rate per day.
            The foxes depend on the chickens for food. Each fox eats one chicken per day.
            Foxes also reproduce at a steady percentage rate per day, but slower than the chickens.
            
            Create two modules named 'fox' and 'chicken'.
            
            The fox module should use these variable names:
            reproductionRate, count,
            reproduction

            The chicken module should use these variable names:
            reproductionRate, count,
            foxCount
            reproduction, predation
            `,
            [
                {
                    name: "Ecosystem Dynamics",
                    requiredStocks: ["fox.count", "chicken.count"]
                },
                {
                    name: "Reproduction Dynamics",
                    requiredVariables: [
                        { name: "fox.reproductionRate" },
                        { name: "chicken.reproductionRate" }
                    ],
                    requiredFlows: ["fox.reproduction", "chicken.reproduction"],
                    requiredRelationships: [
                        { from: "fox.reproductionRate", to: "fox.reproduction", polarity: "+" },
                        { from: "fox.reproduction", to: "fox.count", polarity: "+" },
                        { from: "chicken.reproductionRate", to: "chicken.reproduction", polarity: "+" },
                        { from: "chicken.reproduction", to: "chicken.count", polarity: "+" }
                    ]
                },
                {
                    name: "Predation Dynamics",
                    requiredVariables: [
                        { name: "chicken.foxCount", crossLevelGhostOf: "fox.count" },
                    ],
                    requiredFlows: ["chicken.predation"],
                    requiredRelationships: [
                        { from: "chicken.foxCount", to: "chicken.predation", polarity: "+" },
                        { from: "chicken.predation", to: "chicken.count", polarity: "-" }
                    ]
                }
            ],
            ["chicken", "fox"],
        )
    ],
    "threeModules": [

    ]
};